## 4. gRPC Proto 정의

파일 위치: `/protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// =============================================
// Profile Service
// =============================================

service ProfileService {
  // 프로필 조회
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);

  // 프로필 수정 (부분 수정 지원)
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);

  // 프로필 이미지 삭제
  rpc DeleteProfileImage(DeleteProfileImageRequest) returns (DeleteProfileImageResponse);
}

// =============================================
// Enum 정의
// =============================================

enum Gender {
  GENDER_UNSPECIFIED = 0;
  GENDER_MALE = 1;
  GENDER_FEMALE = 2;
  GENDER_OTHER = 3;
}

enum PurposeType {
  PURPOSE_UNSPECIFIED = 0;
  PURPOSE_FRIENDSHIP = 1;
  PURPOSE_DATING = 2;
  PURPOSE_NETWORKING = 3;
}

// =============================================
// Message 정의 (공통)
// =============================================

message ProfileImage {
  string id = 1;
  string url = 2;
  int32 order = 3;
  bool is_main = 4;
}

message Region {
  string city = 1;
  string district = 2;
  string display_name = 3;
  string region_code = 4;
}

message InterestTag {
  string id = 1;
  string name = 2;
}

message Profile {
  string user_id = 1;
  string nickname = 2;
  optional string bio = 3;
  Gender gender = 4;
  int32 birth_year = 5;
  int32 age = 6;
  optional Region region = 7;
  repeated ProfileImage profile_images = 8;
  optional string main_profile_image_url = 9;
  optional string voice_intro_url = 10;
  repeated PurposeType purposes = 11;
  repeated InterestTag interests = 12;
  optional int32 height = 13;
  optional string occupation = 14;
  bool is_profile_complete = 15;
  string updated_at = 16;
}

// =============================================
// GetProfile
// =============================================

message GetProfileRequest {
  // 조회 요청자 (본인 조회 또는 권한 확인용)
  string requester_user_id = 1;
  // 조회 대상 (생략 시 requester 본인 조회)
  optional string target_user_id = 2;
}

message GetProfileResponse {
  Profile profile = 1;
}

// =============================================
// UpdateProfile
// =============================================

// 이미지 순서 변경
message ProfileImageOrder {
  string image_id = 1;
  int32 order = 2;
}

message UpdateProfileRequest {
  string user_id = 1;

  // 부분 수정: optional 필드는 값이 있을 때만 업데이트
  optional string nickname = 2;
  optional string bio = 3;
  optional string region_code = 4;
  repeated ProfileImageOrder image_orders = 5;
  optional string voice_intro_url = 6;
  // purposes가 빈 배열이면 무시, 1개 이상이면 전체 교체
  repeated PurposeType purposes = 7;
  // interest_tag_ids가 빈 배열이면 무시, 1개 이상이면 전체 교체
  repeated string interest_tag_ids = 8;
  optional int32 height = 9;
  optional string occupation = 10;

  // 업데이트 마스크 (어떤 필드를 실제로 업데이트할지 명시)
  // 예: ["nickname", "bio", "purposes"]
  repeated string update_mask = 11;
}

message UpdateProfileResponse {
  Profile profile = 1;
}

// =============================================
// DeleteProfileImage
// =============================================

message DeleteProfileImageRequest {
  string user_id = 1;
  string image_id = 2;
}

message DeleteProfileImageResponse {
  bool success = 1;
  repeated ProfileImage remaining_images = 2;
}
